              var H = canvasEl.height = canvasEl.offsetHeight * (window.devicePixelRatio || 1);
              var ctx = canvasEl.getContext('2d');
              var dpr = window.devicePixelRatio || 1;

              // World state
              var world = { organisms: [], food: [], lightZones: [], tick: 0 };
              var cam = { x: 0, y: 0, zoom: 1 };
