                            if (isNaN(px) || isNaN(pz)) return;
                            if (plotterWaypoints.length >= 5) return;
                            plotterWaypoints.push({ x: px / 10, z: pz / 10 }); // convert grid coords to world coords
                            xIn.value = ''; zIn.value = '';
