                // Skin gradient for realistic shading
                var skinGrad = ctx.createLinearGradient(W * 0.3, 0, W * 0.7, H);
                skinGrad.addColorStop(0, '#f5e6d3');
                skinGrad.addColorStop(0.3, '#f0ddd0');
                skinGrad.addColorStop(0.6, '#ebd5c6');
